// Get historical price data
const data = $input.item.json;

// Check if data exists
if (!data.values || data.values.length === 0) {
  return { json: { error: "No price data available", ticker: data.meta?.symbol } };
}

// Convert prices to numbers
const prices = data.values.map(v => parseFloat(v.close)).reverse();

// Function to calculate Fibonacci levels
function calculateFibonacciLevels() {
  // Find min and max prices
  const max = Math.max(...prices);
  const min = Math.min(...prices);
  const diff = max - min;

  return {
    level_0: min.toFixed(2),
    level_0_236: (min + diff * 0.236).toFixed(2),
    level_0_382: (min + diff * 0.382).toFixed(2),
    level_0_5: (min + diff * 0.5).toFixed(2),
    level_0_618: (min + diff * 0.618).toFixed(2),
    level_0_786: (min + diff * 0.786).toFixed(2),
    level_1: max.toFixed(2)
  };
}
// Function to identify support and resistance levels
function findSupportResistanceLevels() {
  // We need at least 30 data points
  if (prices.length < 30) {
    return { support: [], resistance: [] };
  }

  const supportLevels = [];
  const resistanceLevels = [];

  // Check each point (except edges) if it's a local minimum or maximum
  const lookback = 5; // how many points to check in each direction

  for (let i = lookback; i < prices.length - lookback; i++) {
    // Check for local minimum (support)
    let isMinimum = true;
    for (let j = i - lookback; j < i; j++) {
      if (prices[j] <= prices[i]) {
        isMinimum = false;
        break;
      }
    }

    for (let j = i + 1; j <= i + lookback; j++) {
      if (prices[j] <= prices[i]) {
        isMinimum = false;
        break;
      }
    }

    if (isMinimum) {
      supportLevels.push(prices[i]);
    }

    // Check for local maximum (resistance)
    let isMaximum = true;
    for (let j = i - lookback; j < i; j++) {
      if (prices[j] >= prices[i]) {
        isMaximum = false;
        break;
      }
    }

    for (let j = i + 1; j <= i + lookback; j++) {
      if (prices[j] >= prices[i]) {
        isMaximum = false;
        break;
      }
    }

    if (isMaximum) {
      resistanceLevels.push(prices[i]);
    }
  }

  // Sort and remove duplicates
  const uniqueSupports = [...new Set(supportLevels)];
  const uniqueResistances = [...new Set(resistanceLevels)];

  // Return only significant levels (up to 5 of each)
  return {
    support: uniqueSupports.sort((a, b) => b - a).slice(0, 5).map(p => p.toFixed(2)),
    resistance: uniqueResistances.sort((a, b) => a - b).slice(0, 5).map(p => p.toFixed(2))
  };
}

// Calculate levels
const fibonacciLevels = calculateFibonacciLevels();
const supportResistanceLevels = findSupportResistanceLevels();

// Return information with additional stock data
return {
  json: {
    ticker: data.meta.symbol,
    currentPrice: parseFloat(data.values[0].close).toFixed(2),
    fibonacci: fibonacciLevels,
    supportResistance: supportResistanceLevels,
    dataPoints: prices.length
  }
};

// Getting data from different sources
// Checking existence of objects before trying to access them
const items = $input.all();
const fibData = $input.first().json;

// Trying to locate bband and MACD data if they exist
let bbandsData = null;
let macdData = null;

// Trying to check if there is data in additional items
if (items.length > 1 && items[1] && items[1].json) {
  bbandsData = items[1].json;
}

if (items.length > 2 && items[2] && items[2].json) {
  macdData = items[2].json;
}

// Creating data structure for the response - ensure all fields exist
const result = {
  ticker: fibData.ticker || "לא ידוע",
  currentPrice: fibData.currentPrice || "0",
  timestamp: new Date().toISOString(),
  technicalAnalysis: {
    fibonacci: fibData.fibonacci || {},
    supportResistance: fibData.supportResistance || { support: [], resistance: [] },
    bollingerBands: {},
    macd: {}
  }
};

// Adding Bollinger Bands data - only if they exist
if (bbandsData && bbandsData.values && bbandsData.values.length > 0) {
  const bbands = bbandsData.values[0];
  result.technicalAnalysis.bollingerBands = {
    upperBand: parseFloat(bbands.upper_band).toFixed(2),
    middleBand: parseFloat(bbands.middle_band).toFixed(2),
    lowerBand: parseFloat(bbands.lower_band).toFixed(2)
  };
} else if (bbandsData && bbandsData.status === "ok") {
  // If returning another data format
  result.technicalAnalysis.bollingerBands = {
    upperBand: bbandsData.upperBand || bbandsData.upper_band || "0",
    middleBand: bbandsData.middleBand || bbandsData.middle_band || "0",
    lowerBand: bbandsData.lowerBand || bbandsData.lower_band || "0"
  };
}

// Adding MACD data - only if they exist
if (macdData && macdData.values && macdData.values.length > 0) {
  const macd = macdData.values[0];
  result.technicalAnalysis.macd = {
    macd: parseFloat(macd.macd).toFixed(2),
    signal: parseFloat(macd.signal).toFixed(2),
    histogram: parseFloat(macd.hist).toFixed(2)
  };
} else if (macdData && macdData.status === "ok") {
  // If returning another data format
  result.technicalAnalysis.macd = {
    macd: macdData.macd || "0",
    signal: macdData.signal || "0",
    histogram: macdData.histogram || macdData.hist || "0"
  };
}

// Creating summary and recommendation
let bullishFactors = [];
let bearishFactors = [];

// Analyzing Bollinger Bands - only if data exists
const bbands = result.technicalAnalysis.bollingerBands;
if (bbands.upperBand && bbands.lowerBand) {
  const currentPrice = parseFloat(result.currentPrice);
  const upperBand = parseFloat(bbands.upperBand);
  const lowerBand = parseFloat(bbands.lowerBand);

  if (!isNaN(currentPrice) && !isNaN(upperBand) && !isNaN(lowerBand)) {
    if (currentPrice > upperBand) {
      bearishFactors.push("מחיר מעל רצועת בולינגר העליונה - אפשרות לקנייה יתר");
    } else if (currentPrice < lowerBand) {
      bullishFactors.push("מחיר מתחת לרצועת בולינגר התחתונה - אפשרות למכירה יתר");
    }
  }
}

// Analyzing MACD - only if data exists
const macdInfo = result.technicalAnalysis.macd;
if (macdInfo.macd && macdInfo.signal) {
  const macd = parseFloat(macdInfo.macd);
  const signal = parseFloat(macdInfo.signal);

  if (!isNaN(macd) && !isNaN(signal)) {
    if (macd > signal) {
      bullishFactors.push("MACD מעל קו האיתות - אינדיקציה חיובית");
    } else {
      bearishFactors.push("MACD מתחת לקו האיתות - אינדיקציה שלילית");
    }
  }
}

// Analyzing support and resistance levels - only if data exists
const supportResistance = result.technicalAnalysis.supportResistance;
if (supportResistance.support && supportResistance.resistance) {
  const currentPrice = parseFloat(result.currentPrice);

  if (!isNaN(currentPrice)) {
    const supports = supportResistance.support.map(s => parseFloat(s)).filter(s => !isNaN(s));
    const resistances = supportResistance.resistance.map(r => parseFloat(r)).filter(r => !isNaN(r));

    // Finding the closest support level
    let closestSupport = null;
    let minSupportDist = Infinity;
    for (const support of supports) {
      if (support < currentPrice) {
        const dist = currentPrice - support;
        if (dist < minSupportDist) {
          minSupportDist = dist;
          closestSupport = support;
        }
      }
    }

    // Finding the closest resistance level
    let closestResistance = null;
    let minResistanceDist = Infinity;
    for (const resistance of resistances) {
      if (resistance > currentPrice) {
        const dist = resistance - currentPrice;
        if (dist < minResistanceDist) {
          minResistanceDist = dist;
          closestResistance = resistance;
        }
      }
    }

    // Adding support/resistance analysis
    if (closestSupport !== null) {
      const supportPercentage = ((currentPrice - closestSupport) / currentPrice * 100).toFixed(2);
      if (supportPercentage < 5) {
        bullishFactors.push(`המחיר קרוב לרמת תמיכה (${supportPercentage}%) - אפשרות להיפוך כלפי מעלה`);
      }
    }

    if (closestResistance !== null) {
      const resistancePercentage = ((closestResistance - currentPrice) / currentPrice * 100).toFixed(2);
      if (resistancePercentage < 5) {
        bearishFactors.push(`המחיר קרוב לרמת התנגדות (${resistancePercentage}%) - אפשרות להיפוך כלפי מטה`);
      }
    }
  }
}

// Analyzing Fibonacci - only if data exists
const fibonacci = result.technicalAnalysis.fibonacci;
if (fibonacci && Object.keys(fibonacci).length > 0) {
  const currentPrice = parseFloat(result.currentPrice);

  if (!isNaN(currentPrice)) {
    const fibLevels = Object.values(fibonacci).map(level => parseFloat(level)).filter(level => !isNaN(level));
    fibLevels.sort((a, b) => a - b);

    // Checking which Fibonacci level the price is at
    for (let i = 0; i < fibLevels.length - 1; i++) {
      if (currentPrice >= fibLevels[i] && currentPrice <= fibLevels[i+1]) {
        // If the price is close to a Fibonacci resistance level
        if (Math.abs(currentPrice - fibLevels[i+1]) / currentPrice * 100 < 2) {
          bearishFactors.push(`המחיר קרוב לרמת פיבונאצ'י ${[0, 23.6, 38.2, 50, 61.8, 78.6, 100][Math.min(i+1, 6)]}% - אפשרות להתנגדות`);
        }
        // If the price is close to a Fibonacci support level
        if (Math.abs(currentPrice - fibLevels[i]) / currentPrice * 100 < 2) {
          bullishFactors.push(`המחיר קרוב לרמת פיבונאצ'י ${[0, 23.6, 38.2, 50, 61.8, 78.6, 100][Math.min(i, 6)]}% - אפשרות לתמיכה`);
        }
        break;
      }
    }
  }
}

// Adding general recommendation based on factors
let recommendation = "";
if (bullishFactors.length > bearishFactors.length) {
  recommendation = "חיובית";
} else if (bearishFactors.length > bullishFactors.length) {
  recommendation = "שלילית";
} else {
  recommendation = "נייטרלית";
}

// Adding summary to the result
result.summary = {
  recommendation: recommendation,
  bullishFactors: bullishFactors,
  bearishFactors: bearishFactors
};

return { json: result };

// Replaces the former GPT-4o image-analysis step.
// Pulls the numeric RSI from the 'Get RSI' node and produces a small
// quantitative summary in the same shape the old vision node returned,
// so the downstream 'Set Variable' reference keeps working unchanged.
let rsi = null;
try {
  const r = $('Get RSI').first().json;
  const v = (r && r.values && r.values[0] && r.values[0].rsi) ? r.values[0].rsi : null;
  rsi = v !== null ? parseFloat(v) : null;
} catch (e) { rsi = null; }

let rsiState = "neutral";
if (rsi !== null) {
  if (rsi >= 70) rsiState = "overbought";
  else if (rsi <= 30) rsiState = "oversold";
}
const summary = {
  rsiNumeric: rsi,
  rsiState: rsiState,
  source: "twelvedata-rsi",
  note: "Quantitative indicators (RSI/MACD/Bollinger) drive this analysis; chart image is attached separately."
};
return [{ json: { choices: [ { message: { content: JSON.stringify(summary) } } ] } }];
